+type Heading = {level: number, text: string, anchor: string};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+|$)(.*)$/;
+
+/** Generates the table of contents delimited by `<!-- toc -->` markers. */
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const newline = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const start = lines.findIndex((line) => startMarker.test(line));
+    if (start === -1) return text;
+
+    const foundEnd = lines.findIndex((line, index) => index > start && endMarker.test(line));
+    // An unclosed marker is an opt-in marker, not permission to consume the rest
+    // of the note. Insert its closing marker directly after the generated TOC.
+    const end = foundEnd === -1 ? start : foundEnd;
+    const headings = this.getHeadings(lines, start, foundEnd, options);
+    const toc = this.buildToc(lines[start], headings, options);
+    const after = foundEnd === -1 ? lines.slice(start + 1) : lines.slice(end + 1);
+    return [...lines.slice(0, start), ...toc, ...after].join(newline);
+  }
+
+  private getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const usedAnchors = new Map<string, number>();
+    let inYaml = false;
+    let inCodeFence: string | undefined;
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (index === 0 && /^---\\s*$/.test(line)) {
+        inYaml = true;
+        continue;
+      }
+      if (inYaml) {
+        if (/^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+        continue;
+      }
+
+      const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (fence) {
+        const kind = fence[1][0];
+        if (!inCodeFence) inCodeFence = kind;
+        else if (inCodeFence === kind) inCodeFence = undefined;
+        continue;
+      }
+      if (inCodeFence) continue;
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (index > tocStart && (tocEnd === -1 || index < tocEnd))) continue;
+
+      const match = line.match(atxHeading);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+      const rawText = match[2].replace(/[ \	]+#+\\s*$/, '');
+      if (this.isExcluded(rawText, options.excludeHeadings)) continue;
+      const explicitId = rawText.match(/\\s*\\{#([^}]+)\\}\\s*$/);
+      const text = options.useExplicitIds && explicitId ? rawText.slice(0, explicitId.index).trimEnd() : rawText;
+      const base = options.useExplicitIds && explicitId ? explicitId[1] : this.anchorText(text);
+      const count = usedAnchors.get(base) ?? 0;
+      usedAnchors.set(base, count + 1);
+      headings.push({level, text, anchor: count === 0 ? base : `${base}-${count}`});
+    }
+    return headings;
+  }
+
+  private buildToc(marker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const result = [marker, ''];
+    if (options.title) result.push(options.title, '');
+    headings.forEach((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const indicator = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      const label = options.stripFormattingInToc ? this.stripFormatting(heading.text) : heading.text;
+      result.push(`${indent}${indicator} [${label}](#${heading.anchor})`);
+    });
+    result.push('', '<!-- /toc -->', '');
+    return result;
+  }
+
+  private isExcluded(text: string, exclusions: string[]): boolean {
+    const plainText = this.stripFormatting(text);
+    return exclusions.some((value) => {
+      if (value.length > 2 && value.startsWith('/') && value.endsWith('/')) {
+        try { return new RegExp(value.slice(1, -1), 'i').test(plainText); } catch { return false; }
+      }
+      return plainText.localeCompare(value, undefined, {sensitivity: 'accent'}) === 0;
+    });
+  }
+
+  private anchorText(text: string): string {
+    return this.stripFormatting(text)
+        .toLowerCase()
+        .replace(/\\s+/g, '-')
+        .replace(/[^a-z0-9_-]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
+  private stripFormatting(text: string): string {
+    return text
+        .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+        .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+        .replace(/\\[\\[([^]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+        .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+        .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1')
+        .replace(/[`*_~]/g, '')
+        .replace(/<[^>]*>/g, '')
+        .trim();
+  }
+
